div.script:
(function () {
    const root = document.getElementById('mainContent');
    if (!root) {
        return;
    }

    const searchInput = root.querySelector('[data-ksl-search]');
    const chipButtons = Array.from(root.querySelectorAll('[data-ksl-chip]'));
    const cards = Array.from(root.querySelectorAll('[data-ksl-card]'));
    const emptyState = root.querySelector('[data-ksl-empty-state]');
    let activeSpecialty = 'all';

    const normalize = (value) => (value || '').toString().trim().toLowerCase();

    const setChipState = () => {
        chipButtons.forEach((button) => {
            const specialty = normalize(button.dataset.specialty || 'all');
            const isActive = activeSpecialty !== 'all' && specialty === activeSpecialty;
            const isAllActive = specialty === 'all' && activeSpecialty === 'all';
            button.classList.toggle('is-active', isActive || isAllActive);
            button.setAttribute('aria-pressed', String(isActive || isAllActive));
        });
    };

    const hideCard = (card) => {
        if (card.dataset.kslVisible === 'false') {
            return;
        }

        card.dataset.kslVisible = 'false';
        const animation = card.animate([
            { opacity: 1, transform: 'translateY(0) scale(1)' },
            { opacity: 0, transform: 'translateY(10px) scale(0.985)' }
        ], {
            duration: 180,
            easing: 'ease-out',
            fill: 'forwards'
        });

        animation.onfinish = () => {
            if (card.dataset.kslVisible === 'false') {
                card.style.display = 'none';
            }
        };
    };

    const showCard = (card, delay = 0) => {
        card.dataset.kslVisible = 'true';
        card.style.display = 'flex';
        card.animate([
            { opacity: 0, transform: 'translateY(12px) scale(0.985)' },
            { opacity: 1, transform: 'translateY(0) scale(1)' }
        ], {
            duration: 220,
            delay,
            easing: 'cubic-bezier(0.22, 1, 0.36, 1)',
            fill: 'forwards'
        });
    };

    const applyFilters = () => {
        const query = normalize(searchInput ? searchInput.value : '');
        let visibleCount = 0;

        cards.forEach((card) => {
            const name = normalize(card.dataset.name);
            const specialty = normalize(card.dataset.specialty);
            const matchesSearch = !query || name.includes(query);
            const matchesSpecialty = activeSpecialty === 'all' || specialty === activeSpecialty;
            const shouldShow = matchesSearch && matchesSpecialty;

            if (shouldShow) {
                visibleCount += 1;
                showCard(card);
            } else {
                hideCard(card);
            }
        });

        if (emptyState) {
            emptyState.hidden = visibleCount !== 0;
        }
    };

    searchInput?.addEventListener('input', applyFilters);

    chipButtons.forEach((button) => {
        button.addEventListener('click', () => {
            const specialty = normalize(button.dataset.specialty || 'all');
            activeSpecialty = activeSpecialty === specialty ? 'all' : specialty;
            setChipState();
            applyFilters();
        });
    });

    setChipState();
    cards.forEach((card, index) => {
        window.setTimeout(() => {
            showCard(card, 0);
        }, index * 70);
    });
})();
